class TCP:
    __ip = "172.20.101.231"
    __port = 5000

    def __init__(self):
        self.__socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.__socket.bind((self.__ip, self.__port))
        self.send_queue = Queue()
        self.receive_queue = deque()

    def send_thread(self):
        while True:
            if not self.send_queue:
                data = self.send_queue.get()
                self.__socket.sendall(data.encode())

    def receive_thread(self):
        while True:
            data = self.__socket.recv(8)
            if not data:
                continue
            speed = int.from_bytes(data[:4],"big")
            angle = int.from_bytes(data[4:],"big")
            self.receive_queue.append((speed,angle))
            print(speed,angle)

    def receive_data(self):
        return self.receive_queue.copy()

    def send_data(self,message):
        self.send_queue.put(message)

    def run(self):
        self.__socket.listen(1)
        print("Waiting for a connection...")
        connection, client_address = self.__socket.accept()
        self.__socket = connection
        self.__socket.setblocking(True)
        print("Connection from", client_address)
        receive_thread = threading.Thread(target=self.receive_thread)
        receive_thread.start()


class MessageGeneration:

    @staticmethod
    def generate_sensor_data(speed,battery):
        json_string = {}
        if battery != battery:
            json_string["battery"] = battery
            battery = battery
        elif speed != speed:
            json_string["speed"] = speed
            speed = speed

        return json.dumps(json_string)

    @staticmethod
    def generate_warning_data(warning_code):
        json_string = {}
        if warning_code != warning_code:
            json_string["warning_code"] = warning_code
            warning_code = warning_code

        return json.dumps(json_string)


class MinimalPublisher(Node):

    def __init__(self):
        super().__init__('local_planner')
        self.publisher = self.create_publisher(Objective, 'hardware_server/socket/objective', 10)
        
        timer_period = 1/10
        self.timer_receive = self.create_timer(timer_period, self.timer_receive_callback)
        
        timer_period = 1/5
        self.timer_send = self.create_timer(timer_period, self.timer_send_callback)
        
        self.subscription_information = self.create_subscription(
            Information, 
            'central_point/safety_guard/info', 
            self.callback_information, 
            10)

        # TODO uncomment me
        # self.socket = TCP()

        self.emergency_stop = False
        self.velocity = 0
        self.battery_level = 0
        
    def callback_information(self, msg):
        self.get_logger().info(f'I heard info value: "{msg.emergency_stop}, {msg.velocity}"')
        self.emergency_stop = msg.emergency_stop
        self.velocity = msg.velocity
        
    def timer_receive_callback(self):
        msg = Objective()
